"use strict";(self.webpackChunkpims_manual=self.webpackChunkpims_manual||[]).push([[8581],{5610:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/pimsKB/docs/intro","docId":"intro","unlisted":false},{"type":"category","label":"Appendix","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Appendix A \u2013 Course Codes","href":"/pimsKB/docs/Appendix/appendix-A","docId":"Appendix/appendix-A","unlisted":false},{"type":"link","label":"Appendix AA \u2013 Categories to Use in the Location  Fact Template for Safe Schools","href":"/pimsKB/docs/Appendix/appendix-AA","docId":"Appendix/appendix-AA","unlisted":false},{"type":"link","label":"Appendix AB \u2013 Categories to Use in the District  Fact Template for Safe Schools","href":"/pimsKB/docs/Appendix/appendix-AB","docId":"Appendix/appendix-AB","unlisted":false},{"type":"link","label":"Appendix AE \u2013 Categories to Use in the District  Fact Template for Title I","href":"/pimsKB/docs/Appendix/appendix-AE","docId":"Appendix/appendix-AE","unlisted":false},{"type":"link","label":"appendix-AF","href":"/pimsKB/docs/Appendix/appendix-AF","docId":"Appendix/appendix-AF","unlisted":false},{"type":"link","label":"Appendix B \u2013 Staff Assignment Codes","href":"/pimsKB/docs/Appendix/appendix-B","docId":"Appendix/appendix-B","unlisted":false},{"type":"link","label":"Appendix C \u2013 Highest Level of Education Completed","href":"/pimsKB/docs/Appendix/appendix-C","docId":"Appendix/appendix-C","unlisted":false},{"type":"link","label":"Appendix D \u2013 State and County Codes","href":"/pimsKB/docs/Appendix/appendix-D","docId":"Appendix/appendix-D","unlisted":false},{"type":"link","label":"Appendix E \u2013 Enrollment and Withdrawal Codes","href":"/pimsKB/docs/Appendix/appendix-E","docId":"Appendix/appendix-E","unlisted":false},{"type":"link","label":"Appendix F \u2013 Program Codes","href":"/pimsKB/docs/Appendix/appendix-F","docId":"Appendix/appendix-F","unlisted":false},{"type":"link","label":"Appendix G \u2013 Employment Eligibility Verification Codes","href":"/pimsKB/docs/Appendix/appendix-G","docId":"Appendix/appendix-G","unlisted":false},{"type":"link","label":"Appendix H \u2013 Disability Codes (Challenge Types)","href":"/pimsKB/docs/Appendix/appendix-H","docId":"Appendix/appendix-H","unlisted":false},{"type":"link","label":"Appendix J \u2013 Language Codes","href":"/pimsKB/docs/Appendix/appendix-J","docId":"Appendix/appendix-J","unlisted":false},{"type":"link","label":"Appendix K \u2013 Grade Level","href":"/pimsKB/docs/Appendix/appendix-K","docId":"Appendix/appendix-K","unlisted":false},{"type":"link","label":"Appendix L \u2013 Student Status","href":"/pimsKB/docs/Appendix/appendix-L","docId":"Appendix/appendix-L","unlisted":false},{"type":"link","label":"Appendix M \u2013 Expected Post Graduate and Post Dropout Activity","href":"/pimsKB/docs/Appendix/appendix-M","docId":"Appendix/appendix-M","unlisted":false},{"type":"link","label":"Appendix N \u2013 Residency Status and District Codes","href":"/pimsKB/docs/Appendix/appendix-N","docId":"Appendix/appendix-N","unlisted":false},{"type":"link","label":"Appendix O \u2013 Semester Values","href":"/pimsKB/docs/Appendix/appendix-O","docId":"Appendix/appendix-O","unlisted":false},{"type":"link","label":"Appendix P \u2013 CTE Status Type Codes","href":"/pimsKB/docs/Appendix/appendix-P","docId":"Appendix/appendix-P","unlisted":false},{"type":"link","label":"Appendix Q \u2013 Industry Credential (Certification) Codes","href":"/pimsKB/docs/Appendix/appendix-Q","docId":"Appendix/appendix-Q","unlisted":false},{"type":"link","label":"Appendix R \u2013 Calendar Program Codes","href":"/pimsKB/docs/Appendix/appendix-R","docId":"Appendix/appendix-R","unlisted":false},{"type":"link","label":"Appendix S \u2013 Family Educational Rights and Privacy Act","href":"/pimsKB/docs/Appendix/appendix-S","docId":"Appendix/appendix-S","unlisted":false},{"type":"link","label":"Appendix U \u2013 Educational Environment","href":"/pimsKB/docs/Appendix/appendix-U","docId":"Appendix/appendix-U","unlisted":false},{"type":"link","label":"Appendix V \u2013 Reason for Exiting Special Education","href":"/pimsKB/docs/Appendix/appendix-V","docId":"Appendix/appendix-V","unlisted":false},{"type":"link","label":"Appendix X \u2013 Officer Definitions","href":"/pimsKB/docs/Appendix/appendix-X","docId":"Appendix/appendix-X","unlisted":false},{"type":"link","label":"Appendix Y \u2013 Incident Place Codes","href":"/pimsKB/docs/Appendix/appendix-Y","docId":"Appendix/appendix-Y","unlisted":false},{"type":"link","label":"Appendix Z \u2013 Infraction Codes","href":"/pimsKB/docs/Appendix/appendix-Z","docId":"Appendix/appendix-Z","unlisted":false}]},{"type":"category","label":"Templates","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Enrollment","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"School Enrollment Template","href":"/pimsKB/docs/Templates/Enrollment/school-enrollment-template","docId":"Templates/Enrollment/school-enrollment-template","unlisted":false}]},{"type":"link","label":"Templates","href":"/pimsKB/docs/Templates/intro","docId":"Templates/intro","unlisted":false}]},{"type":"link","label":"Courses to be Reported in PIMS","href":"/pimsKB/docs/courses-to-be-reported","docId":"courses-to-be-reported","unlisted":false},{"type":"link","label":"Curriculum, Assessment, and Instruction","href":"/pimsKB/docs/curriculum-assessment-instruction","docId":"curriculum-assessment-instruction","unlisted":false},{"type":"link","label":"Race, Ethnicity, Gender","href":"/pimsKB/docs/race-ethnicity-gender-standards","docId":"race-ethnicity-gender-standards","unlisted":false},{"type":"link","label":"Staff to be Reported in PIMS","href":"/pimsKB/docs/staff-to-be-reported","docId":"staff-to-be-reported","unlisted":false},{"type":"link","label":"Students to be Reported in PIMS","href":"/pimsKB/docs/students-to-be-reported","docId":"students-to-be-reported","unlisted":false}]},"docs":{"Appendix/appendix-A":{"id":"Appendix/appendix-A","title":"Appendix A \u2013 Course Codes","description":"Course Codes are found in the Course Codes \u2013 App A spreadsheet on the Pennsylvania Department of Education \\\\> Data and Reporting \\\\> PIMS \\\\> Manuals and Calendar page.","sidebar":"tutorialSidebar"},"Appendix/appendix-AA":{"id":"Appendix/appendix-AA","title":"Appendix AA \u2013 Categories to Use in the Location  Fact Template for Safe Schools","description":"The tables below detail the values to use in the CATEGORY 1 \u2013 CATEGORY 4 fields as well as the COUNT field when reporting habitual truancy and the indication of no reportable School Safety incidents.","sidebar":"tutorialSidebar"},"Appendix/appendix-AB":{"id":"Appendix/appendix-AB","title":"Appendix AB \u2013 Categories to Use in the District  Fact Template for Safe Schools","description":"The table below details the values to use in the CATEGORY 1 and CATEGORY 2 fields as well as the COUNT field when reporting zero directly employed or contracted security staff. Alternately, if an LEA contracts with a security company that rotates staff, the values to use in the CATEGORY 1, CATEGORY 2, and COUNT fields for the various aggregate security staff counts are listed.","sidebar":"tutorialSidebar"},"Appendix/appendix-AE":{"id":"Appendix/appendix-AE","title":"Appendix AE \u2013 Categories to Use in the District  Fact Template for Title I","description":"-   Appendix AE is for use with Field 3 (CATEGORY 1), Field 4 (CATEGORY 2), Field 5 (CATEGORY 3), Field 6 (MEASURE TYPE), and Field 11 (CATEGORY 4) in the District Fact Template,","sidebar":"tutorialSidebar"},"Appendix/appendix-AF":{"id":"Appendix/appendix-AF","title":"appendix-AF","description":"","sidebar":"tutorialSidebar"},"Appendix/appendix-B":{"id":"Appendix/appendix-B","title":"Appendix B \u2013 Staff Assignment Codes","description":"Chief School Administrator Assignment Codes (numerical order) are found in the Staff Assignments \u2013","sidebar":"tutorialSidebar"},"Appendix/appendix-C":{"id":"Appendix/appendix-C","title":"Appendix C \u2013 Highest Level of Education Completed","description":"Appendix C is for use with Field 71 (HIGHEST DEGREE INSTITUTION CODE) in the Staff and Staff Snapshot Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-D":{"id":"Appendix/appendix-D","title":"Appendix D \u2013 State and County Codes","description":"State Codes","sidebar":"tutorialSidebar"},"Appendix/appendix-E":{"id":"Appendix/appendix-E","title":"Appendix E \u2013 Enrollment and Withdrawal Codes","description":"The codes listed below are only to be used for Field 6 (ENROLLMENT CODE) in the School Enrollment Template. These codes do not replace any existing codes that may be native to your local Student Information System (SIS). Please continue to use enrollment codes in your SIS which support other purposes, such as Child Accounting aggregate calculations, scheduling changes, room changes, etc. The codes listed in the table below are the only codes that will be accepted in the School Enrollment Template submission to PIMS.","sidebar":"tutorialSidebar"},"Appendix/appendix-F":{"id":"Appendix/appendix-F","title":"Appendix F \u2013 Program Codes","description":"The programs listed below are tracked using the Program Fact Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-G":{"id":"Appendix/appendix-G","title":"Appendix G \u2013 Employment Eligibility Verification Codes","description":"Appendix G is for use with Field 83 (EMPLOYMENT ELIGIBILITY VERIFICATION) in the Staff and Staff Snapshot Templates.","sidebar":"tutorialSidebar"},"Appendix/appendix-H":{"id":"Appendix/appendix-H","title":"Appendix H \u2013 Disability Codes (Challenge Types)","description":"Appendix H is for use with Field 34 (CHALLENGE TYPE) in the Student and Student Snapshot Templates, and Field 11 (PRIMARY DISABILITY) and Field 12 (SECONDARY DISABILITY) in the Special Education Snapshot Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-J":{"id":"Appendix/appendix-J","title":"Appendix J \u2013 Language Codes","description":"Language Codes are found on the Language Codes \u2013 Appendix J spreadsheet on the Pennsylvania Department of Education \\\\> Data and Reporting \\\\> PIMS \\\\> Manuals and Calendar page.","sidebar":"tutorialSidebar"},"Appendix/appendix-K":{"id":"Appendix/appendix-K","title":"Appendix K \u2013 Grade Level","description":"Appendix K is for use with Field 11 (CURRENT GRADE LEVEL) in the Student Calendar Fact Template; Field 7 (GRADE LEVEL CODE AT TIME OF INCIDENT) in the Incident Offender Template; Field 7 (GRADE LEVEL CODE AT TIME OF INCIDENT) in the Incident Victim Template; Field 9 (ENROLLMENT GRADE LEVEL) in the School Enrollment Template; Field 10 (CURRENT GRADE LEVEL) in the Student and Student Snapshot Templates; and Field 5 (SUBTEST GRADE LEVEL) in the Student Local Assessment Subtest Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-L":{"id":"Appendix/appendix-L","title":"Appendix L \u2013 Student Status","description":"Appendix L is for use with Field 67 (STUDENT STATUS) in the Student and Student Snapshot Templates. See Appendix N for Residence Status Codes.","sidebar":"tutorialSidebar"},"Appendix/appendix-M":{"id":"Appendix/appendix-M","title":"Appendix M \u2013 Expected Post Graduate and Post Dropout Activity","description":"Appendix M is for use with Field 66 (EXPECTED POST-GRADUATE ACTIVITY) in the Student and Student Snapshot Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-N":{"id":"Appendix/appendix-N","title":"Appendix N \u2013 Residency Status and District Codes","description":"Appendix N is for use with Field 5 (DISTRICT OF RESIDENCE AUN), Field 6 (FUNDING DISTRICT AUN), and Field 7 (RESIDENCE STATUS CODE) for the Student Calendar Fact Template; Field 10 (RESIDENCE STATUS CODE) for the School Enrollment Template; and Field 117 (DISTRICT OF RESIDENCE AUN) and Field 189 (FUNDING DISTRICT AUN) in the Student and Student Snapshot Templates.","sidebar":"tutorialSidebar"},"Appendix/appendix-O":{"id":"Appendix/appendix-O","title":"Appendix O \u2013 Semester Values","description":"Appendix O is for use with Field 17 (SUPPLEMENTARY COURSE DIFFERENTIATOR (formerly named \u201cSEMESTER\u201d)) in the Student Course Enrollment Template and Field 17 (SUPPLEMENTARY COURSE DIFFERENTIATOR) in the Course Instructor Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-P":{"id":"Appendix/appendix-P","title":"Appendix P \u2013 CTE Status Type Codes","description":"Appendix P, for both AAP and Secondary CTE students, is for use with Field 10 (CTE STATUS TYPE CODE) in the CTE Student Fact Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-Q":{"id":"Appendix/appendix-Q","title":"Appendix Q \u2013 Industry Credential (Certification) Codes","description":"Appendix Q is for use with Field 7 (INDUSTRY CREDENTIAL CODE) in the Student Industry Credential Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-R":{"id":"Appendix/appendix-R","title":"Appendix R \u2013 Calendar Program Codes","description":"Calendar Program Code is Field 8 (CALENDAR PROGRAMS CODE) in the School Calendar Template. The purpose of the code is to identify a student\u2019s days enrolled in a specific program. The data is used in subsidy calculations.","sidebar":"tutorialSidebar"},"Appendix/appendix-S":{"id":"Appendix/appendix-S","title":"Appendix S \u2013 Family Educational Rights and Privacy Act","description":"Student education records are official and confidential documents protected by one of the nation\'s strongest privacy protection laws, the Family Educational Rights and Privacy Act (FERPA). FERPA, also known as the Buckley Amendment, defines education records as all records that schools or education agencies maintain about students.","sidebar":"tutorialSidebar"},"Appendix/appendix-U":{"id":"Appendix/appendix-U","title":"Appendix U \u2013 Educational Environment","description":"eScholar Lookup \u2013 PRIMARY SETTING CODE","sidebar":"tutorialSidebar"},"Appendix/appendix-V":{"id":"Appendix/appendix-V","title":"Appendix V \u2013 Reason for Exiting Special Education","description":"eScholar Lookup \u2013 PRIMARY EXIT REASON CODE","sidebar":"tutorialSidebar"},"Appendix/appendix-X":{"id":"Appendix/appendix-X","title":"Appendix X \u2013 Officer Definitions","description":"Appendix X is for use with Field 48 (STAFF QUALIFICATION STATUS CODE).","sidebar":"tutorialSidebar"},"Appendix/appendix-Y":{"id":"Appendix/appendix-Y","title":"Appendix Y \u2013 Incident Place Codes","description":"Appendix Y is for use with Field 7 (INCIDENT PLACE CODE) in the Incident Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-Z":{"id":"Appendix/appendix-Z","title":"Appendix Z \u2013 Infraction Codes","description":"Appendix Z is for use with Field 4 (INFRACTION CODE) in the Incident Offender Infraction Template.","sidebar":"tutorialSidebar"},"courses-to-be-reported":{"id":"courses-to-be-reported","title":"Courses to be Reported in PIMS","description":"LEAs are required to submit all courses, course instructor assignments, and student course enrollments, in all academic subject areas for both elementary and secondary. To meet federal reporting requirements, LEAs are expected to map all local courses to state course codes (PIMS \\\\> Manuals and Calendar \\\\> Course Codes \u2013 App A).","sidebar":"tutorialSidebar"},"curriculum-assessment-instruction":{"id":"curriculum-assessment-instruction","title":"Curriculum, Assessment, and Instruction","description":"Division of Assessment and Accountability (DAA)","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"The Pennsylvania Information Management System (PIMS) is a collaborative effort of the Pennsylvania Department of Education (PDE) and local education agencies (LEA) across the commonwealth. PIMS is a statewide, longitudinal data system (SLDS) that efficiently and accurately manages, analyzes, disaggregates, and uses individual data for each student served by Pennsylvania\u2019s pre-K through grade 12 public education system.","sidebar":"tutorialSidebar"},"race-ethnicity-gender-standards":{"id":"race-ethnicity-gender-standards","title":"Race, Ethnicity, Gender","description":"Federal Race, Ethnicity, and Gender Standards","sidebar":"tutorialSidebar"},"staff-to-be-reported":{"id":"staff-to-be-reported","title":"Staff to be Reported in PIMS","description":"Professional Personnel","sidebar":"tutorialSidebar"},"students-to-be-reported":{"id":"students-to-be-reported","title":"Students to be Reported in PIMS","description":"All Pre-K through grade 12 and Adult Affidavit Program (AAP) students enrolled in a public school and students enrolled in an Approved Private School (APS) or Private Residential Rehabilitation Institution (PRRI) in Pennsylvania shall be reported in PIMS. Student data will be submitted through templates. See the template section of this document for more information.","sidebar":"tutorialSidebar"},"Templates/Enrollment/school-enrollment-template":{"id":"Templates/Enrollment/school-enrollment-template","title":"School Enrollment Template","description":"School Enrollment Template Documentation","sidebar":"tutorialSidebar"},"Templates/intro":{"id":"Templates/intro","title":"Templates","description":"Templates are the files that will be used to load data into the PIMS data warehouse. Template specifications define the fields required for each file submitted to PIMS. Each template maps directly to a separate table in the data warehouse. By using templates, LEAs are able to use a variety of file formats (comma delimited, tab delimited, pipe) to transmit data as long as all fields within the template are accounted for. Within a given template not all eScholar-defined fields are collected by PDE.","sidebar":"tutorialSidebar"}}}')}}]);